diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 3f3f6c6e0d1a..eb2901b339e1 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -4612,6 +4612,78 @@ static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
   // select ?, X, X -> X
   if (TrueVal == FalseVal)
     return TrueVal;
+  // Helper to check if a value is guaranteed not to be poison
+  auto isNotPoison = [&Q](Value *V) {
+    return isGuaranteedNotToBePoison(V, Q.AC, Q.CxtI, Q.DT);
+  };
+
+  // select (select A, B, false), true, B -> B  -- (A && B) || B = B
+
+  // select (select A, B, true), false, B -> B  -- (A || B) && B = B
+  if (Cond->getType() == TrueVal->getType()) {
+    Value *A, *B;
+    Constant *C;
+    if (match(Cond, m_Select(m_Value(A), m_Value(B), m_Constant(C))) &&
+        match(TrueVal, m_One()) && match(FalseVal, m_Specific(B)) &&
+        isNotPoison(C))
+      return B;
+    if (match(Cond, m_Select(m_Value(A), m_Value(B), m_Constant(C))) &&
+        match(TrueVal, m_ZeroInt()) && match(FalseVal, m_Specific(B)) &&
+        isNotPoison(C))
+      return B;
+  }
+  // select Y, true, (select X, Y, false) -> Y  -- Y || (X && Y) = Y
+  // select Y, false, (select X, Y, true) -> Y  -- Y && (X || Y) = Y
+  if (Cond->getType() == FalseVal->getType()) {
+    Value *X, *Y;
+    Constant *C;
+    if (match(FalseVal, m_Select(m_Value(X), m_Specific(Cond), m_Constant(C))) &&
+        match(TrueVal, m_One()) && isNotPoison(C))
+      return Cond;
+    if (match(FalseVal, m_Select(m_Value(X), m_Specific(Cond), m_Constant(C))) &&
+        match(TrueVal, m_ZeroInt()) && isNotPoison(C))
+      return Cond;
+  }
+  // select (select Y, X, false), true, Y -> Y  -- (Y && X) || Y = Y
+  // select (select Y, X, true), false, Y -> Y  -- (Y || X) && Y = Y
+  if (Cond->getType() == TrueVal->getType()) {
+    Value *X, *Y;
+    Constant *C;
+    if (match(Cond, m_Select(m_Specific(FalseVal), m_Value(X), m_Constant(C))) &&
+        match(TrueVal, m_One()) && isNotPoison(C))
+      return FalseVal;
+    if (match(Cond, m_Select(m_Specific(FalseVal), m_Value(X), m_Constant(C))) &&
+        match(TrueVal, m_ZeroInt()) && isNotPoison(C))
+      return FalseVal;
+  }
+  // select Y, true, (select Y, X, false) -> Y  -- Y || (Y && X) = Y
+  // select Y, false, (select Y, X, true) -> Y  -- Y && (Y || X) = Y
+  if (Cond->getType() == FalseVal->getType()) {
+    Value *X, *Y;
+    Constant *C;
+    if (match(FalseVal, m_Select(m_Specific(Cond), m_Value(X), m_Constant(C))) &&
+        match(TrueVal, m_One()) && isNotPoison(C))
+      return Cond;
+    if (match(FalseVal, m_Select(m_Specific(Cond), m_Value(X), m_Constant(C))) &&
+        match(TrueVal, m_ZeroInt()) && isNotPoison(C))
+      return Cond;
+  }
+
+  // select X, true, (X && Y) -> X  -- X || (X && Y) = X
+  // select X, false, (X || Y) -> X  -- X && (X || Y) = X
+  if (Cond->getType() == TrueVal->getType()) {
+    Value *X, *Y;
+    if (match(Cond, m_Specific(FalseVal)) && match(TrueVal, m_One()))
+      return Cond;
+    // select X, true, (and X, Y) -> X
+    if (match(TrueVal, m_One()) &&
+        match(FalseVal, m_c_LogicalAnd(m_Specific(Cond), m_Value())))
+      return Cond;
+    // select X, false, (or X, Y) -> X
+    if (match(TrueVal, m_ZeroInt()) &&
+        match(FalseVal, m_c_LogicalOr(m_Specific(Cond), m_Value())))
+      return Cond;
+  }

   if (Cond == TrueVal) {
     // select i1 X, i1 X, i1 false --> X (logical-and)
